import{_ as n,o as r,c as t,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const N=JSON.parse('{"title":"电吉他-奈文（Nevan）","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/电吉他-奈文（Nevan）.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/电吉他-奈文（Nevan）.md"}'),p={name:"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/电吉他-奈文（Nevan）.md"};function d(_,a,l,i,v,c){return r(),t("div",null,[...a[0]||(a[0]=[e("h1",{id:"电吉他-奈文-nevan",tabindex:"-1"},[s("电吉他-奈文（Nevan） "),e("a",{class:"header-anchor",href:"#电吉他-奈文-nevan","aria-label":'Permalink to "电吉他-奈文（Nevan）"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风026")])])],-1),o('<h1 id="电吉他-奈文-nevan-1" tabindex="-1">电吉他-奈文（Nevan） <a class="header-anchor" href="#电吉他-奈文-nevan-1" aria-label="Permalink to &quot;电吉他-奈文（Nevan）&quot;">​</a></h1><p>电吉他奈文(Nevan)<br> 魔幻本质<br> 价格：D+500</p><p>奈文（Nevan) : 一把拥有闪电力量的电吉他，整体为深紫色，缠绕着雷电，其上半部分可以展开变为带有锋利锯刃的镰刀。奈文（Nevan)是一把变形武器，拥有两种形态</p><p>人物使用这把电吉他时，以风度+表达+乐器+辅助专业：乐理学进行攻击，电吉他形态下，射程15米，伤害为6L。随着演奏，吉他会激发出雷电蝙蝠，向着目标去飞去，造成雷电伤害。</p><p>以一个花招动作切换为镰刀形态，此时，原本琴颈部分变为镰刀的手柄，而琴身部位将从琴桥向外展开，变为锋利的锯刃镰刀，镰刀状态下，具有伤害7L，演奏攻击将如使用【巨镰】般攻击触及敌人，并造成物理-挥砍伤害。</p><p>【Turn-Up】：在电吉他形态下，电吉他-奈文(Nevan)可以通过一次任意的演奏攻击提高音量，从而召唤处更多的雷电蝙蝠攻击，这视为奈文(Nevan)在那次攻击之后获得【短点射】，随后一场景内，奈文(Nevan)在任意形态下，都可以保留短点射提供的加值。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const b=n(p,[["render",d]]);export{N as __pageData,b as default};
